import java.io.*;

public class SecureDeserializationExample {

    public static void main(String[] args) {
        String userInput = "filename.ser"; // User input for the serialized file

        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(userInput))) {
            ois.setObjectInputFilter(new SecureObjectInputFilter()); // Set custom ObjectInputFilter
            Object obj = ois.readObject();
            System.out.println("Deserialized object: " + obj);
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }

    static class SecureObjectInputFilter implements ObjectInputFilter {
        @Override
        public Status checkInput(FilterInfo filterInfo) {
            if (filterInfo.serialClass() != null && !filterInfo.serialClass().getName().startsWith("java")) {
                return Status.REJECTED;
            }
            return Status.UNDECIDED;
        }
    }
}

### Explanation:
취약유형: Insecure Deserialization
